import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function ProductosPorCategoria() {
  const { categoria_id } = useParams();
  const navigate = useNavigate();

  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);

  const obtenerProductos = useCallback(async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria_id}`
      );

      setProductos(
        res.data.map((p) => ({
          id: p.ProductoID ?? p.id,
          nombre: p.Nombre ?? p.nombre,
          descripcion: p.Descripcion ?? p.descripcion,
          precio: p.Precio ?? p.precio,
          imagen: p.Imagen ?? p.imagen,
        }))
      );
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setLoading(false);
    }
  }, [categoria_id]);

  useEffect(() => {
    obtenerProductos();
  }, [obtenerProductos]);

  if (loading) {
    return <p className="text-center mt-5">Cargando...</p>;
  }

  return (
    <div className="container mt-5">
      <button className="btn btn-secondary mb-3" onClick={() => navigate(-1)}>
        ⬅ Volver
      </button>

      <h3 className="mb-4">Productos de la categoría</h3>

      <div className="row">
        {productos.length === 0 && (
          <p className="text-center">No hay productos en esta categoría</p>
        )}

        {productos.map((p) => (
          <div key={p.id} className="col-md-1 mb-1">
            <div className="card h-100 shadow">
              {p.imagen && (
                <img
                  src={`http://localhost:5000/uploads/${p.imagen}`}
                  className="card-img-top"
                  alt={p.nombre}
                  style={{ height: "350px", objectFit: "cover" }}
                />
              )}

              <div className="card-body">
                <h5>{p.nombre}</h5>
                <p>{p.descripcion}</p>
                <strong>${p.precio}</strong>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
